output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?reserve ?reserveLabel WHERE {
  ?reserve wdt:P17 wd:Q928 ; wdt:P814 wd:Q14545608 .
  OPTIONAL {
    ?reserve rdfs:label ?reserveLabel .
    FILTER(lang(?reserveLabel) = 'en')
  }
}
